const char web_page_content[] = "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\"><title>Robot Controller</title><style>body{background:#0f172a;color:#fff;font-family:system-ui,sans-serif;margin:0;height:100vh;display:flex;justify-content:center;align-items:center;user-select:none;-webkit-user-select:none;-webkit-tap-highlight-color:transparent}.p{background:#1e293b;padding:2rem;border-radius:1.5rem;box-shadow:0 10px 25px #0008;text-align:center;width:100%;max-width:260px;border:1px solid #334155}h1{margin:0 0 1.5rem;font-size:1.5rem;color:#e2e8f0;letter-spacing:1px}.g{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:1.5rem}.b{background:#3b82f6;border:none;border-radius:1rem;color:#fff;padding:15px 0;cursor:pointer;display:flex;flex-direction:column;align-items:center;transition:.1s;box-shadow:0 4px 6px -1px #0004}.b:active{transform:scale(.95);background:#2563eb}.r{background:#ef4444;border:2px solid #b91c1c}.r:active{background:#dc2626}svg{width:28px;height:28px;fill:none;stroke:currentColor;stroke-width:2;stroke-linecap:round;stroke-linejoin:round;margin-bottom:4px}span{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.05em}.s{background:#0f172a;padding:12px;border-radius:.75rem;font-family:monospace;font-size:12px;color:#64748b;border:1px solid #334155}.ok{color:#4ade80}.err{color:#ef4444}.snd{color:#22d3ee}</style></head><body><div class=\"p\"><h1>Control Panel</h1><div class=\"g\"><div></div><button id=\"forward\" class=\"b\"><svg viewBox=\"0 0 24 24\"><path d=\"M5 15l7-7 7 7\"/></svg><span>Forward</span></button><div></div><button id=\"turn_left\" class=\"b\"><svg viewBox=\"0 0 24 24\"><path d=\"M10 19l-7-7m0 0l7-7m-7 7h18\"/></svg><span>Left</span></button> <button id=\"brake\" class=\"b r\"><svg viewBox=\"0 0 24 24\"><path d=\"M21 12a9 9 0 11-18 0 9 9 0 0118 0z\"/><path d=\"M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1h-4a1 1 0 01-1-1v-4z\"/></svg><span>Brake</span></button> <button id=\"turn_right\" class=\"b\"><svg viewBox=\"0 0 24 24\"><path d=\"M14 5l7 7m0 0l-7 7m7-7H3\"/></svg><span>Right</span></button><div></div><button id=\"backward\" class=\"b\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 9l-7 7-7-7\"/></svg><span>Backward</span></button><div></div></div><div id=\"l\" class=\"s\">System online.</div></div><script>let l=document.getElementById(\"l\");document.querySelectorAll(\".b\").forEach(e=>{e.onpointerdown=n=>{n.preventDefault();let t=e.id;l.className=\"s snd\",l.innerText=`[GET] /${t}`,fetch(`/${t}`,{mode:\"no-cors\"}).then(()=>{l.className=\"s ok\",l.innerText=`[OK] /${t}`,setTimeout(()=>l.innerText.includes(t)&&(l.className=\"s\",l.innerText=\"Online.\"),1500)}).catch(()=>{l.className=\"s err\",l.innerText=\"[ERR] Network\"})},e.oncontextmenu=e=>e.preventDefault()})</script></body></html>";
